    auto sensorB = std::make_shared<RecordingNode>();
    auto aggregator = std::make_shared<RecordingNode>();

    auto &graph = ObserverGraph::getInstance();
    graph.addNode(sensorA);
    graph.addNode(sensorB);
    graph.addNode(aggregator);

