 * value was changed.
 */
class IntAtomicImpl {
public:
    explicit IntAtomicImpl(int32_t initial);

    template <typename F>
    void atomicOperation(F&& op);

    template <typename F>
    void atomicOperation(F&& op, bool forceNotify);

    int32_t value() const;
    bool lastReportedChange() const;

private:
